# pip install pydantic
from pydantic import BaseModel, Field, EmailStr, field_validator, ValidationError

class User(BaseModel):
    name: str = Field(min_length=1)
    age: int = Field(gt=0, lt=150)
    email: EmailStr           # requires: pip install pydantic[email]
    tags: list[str] = []      # mutable default is safe in Pydantic

    @field_validator("name")
    @classmethod
    def title_case(cls, v: str) -> str:
        return v.strip().title()

# coercion: the string "30" is parsed into an int
u = User(name="  ada lovelace", age="30", email="ada@example.com")
print(u.name, u.age)            # Ada Lovelace 30
print(u.model_dump())          # plain dict, ready to store or return

try:
    User(name="", age=-5, email="not-an-email")
except ValidationError as e:
    print(e.error_count(), "errors")  # one structured error per problem

