from pydantic import model_validator

class Order(BaseModel):
    order_id: int
    customer_email: str
    items: list[LineItem] = Field(min_length=1)
    total: float = 0.0

    @model_validator(mode="after")
    def compute_total(self):
        self.total = round(
            sum(i.quantity * i.unit_price for i in self.items), 2)
        return self

order = Order.model_validate({
    "order_id": 1001, "customer_email": "sam@example.com",
    "items": [{"sku": "ABC", "quantity": 2, "unit_price": 9.99}],
})
print(order.total)  # 19.98

from pydantic import ValidationError

bad = {"order_id": "oops", "customer_email": "x", "items": []}
try:
    Order.model_validate(bad)
except ValidationError as e:
    for err in e.errors():
        print(err["loc"], "->", err["msg"])

