from flask import Flask, request, abort

app = Flask(__name__)
tasks = [{"id": 1, "title": "Learn Flask", "done": False}]

@app.get("/tasks")
def list_tasks():
    return {"tasks": tasks}

@app.get("/tasks/<int:task_id>")
def get_task(task_id: int):
    for t in tasks:
        if t["id"] == task_id:
            return t
    abort(404, description="Task not found")

@app.post("/tasks")
def create_task():
    data = request.get_json()
    new = {"id": len(tasks) + 1, "title": data["title"], "done": False}
    tasks.append(new)
    return new, 201

