from typing import Annotated
from fastapi import Depends, FastAPI

app = FastAPI()

# a reusable dependency: shared pagination params
def pagination(skip: int = 0, limit: int = 20) -> dict:
    return {"skip": skip, "limit": min(limit, 100)}

# name the dependency once, reuse the type everywhere
Page = Annotated[dict, Depends(pagination)]

@app.get("/users")
async def list_users(page: Page):
    return {"page": page}

@app.get("/orders")
async def list_orders(page: Page):
    return {"page": page}

