from pydantic import BaseModel, Field

class Book(BaseModel):
    title: str = Field(min_length=1)
    year: int = Field(gt=0)

@app.post("/books", status_code=201)
async def create_book(book: Book):
    new_id = max(books) + 1 if books else 1
    books[new_id] = {"id": new_id, **book.model_dump()}
    return books[new_id]

from fastapi import HTTPException

@app.get("/books/{book_id}")
async def get_book(book_id: int):
    if book_id not in books:
        raise HTTPException(status_code=404, detail="Book not found")
    return books[book_id]

@app.get("/books")
async def list_books(limit: int = 10):
    return list(books.values())[:limit]

from typing import Annotated
from fastapi import Depends, Header, HTTPException

def require_key(x_api_key: Annotated[str | None, Header()] = None):
    if x_api_key != "secret":
        raise HTTPException(status_code=401, detail="Bad API key")
    return x_api_key

@app.delete("/books/{book_id}", status_code=204)
async def delete_book(book_id: int, _: Annotated[str, Depends(require_key)]):
    books.pop(book_id, None)

