from dash import Dash, html, dcc, callback, Input, Output
import plotly.express as px

app = Dash(__name__)
df = px.data.gapminder()

app.layout = html.Div([
    html.H1("Life Expectancy by Continent"),
    dcc.Dropdown(
        id="continent",
        options=sorted(df["continent"].unique()),
        value="Asia",
    ),
    dcc.Graph(id="chart"),
])

@callback(
    Output("chart", "figure"),     # update the graph's figure...
    Input("continent", "value"),   # ...whenever the dropdown changes
)
def update_chart(continent):
    filtered = df[df["continent"] == continent]
    return px.line(filtered, x="year", y="lifeExp", color="country")

if __name__ == "__main__":
    app.run(debug=True)

